const pageId = String($json.params?.pageId || '').trim();
const token = String($json.query?.t || '').trim();

return [{
  json: {
    pageId,
    token
  }
}];

const row = $input.first().json || {};

const reqPageId = String(row.requested_page_id || '').trim();
const providedToken = String(row.provided_token || '').trim();
const storedToken = String(row.stored_token || '').trim();
const htmlB64 = String(row.html_base64 || '');
const expiresAtRaw = row.expires_at;

const htmlError = (title, text) => `<!doctype html><html lang="de"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>${title}</title><style>body{font-family:ui-sans-serif,-apple-system,Segoe UI,Helvetica,Arial,sans-serif;background:#f4f7fb;color:#1f2937;margin:0;padding:24px}main{max-width:760px;margin:0 auto;background:#fff;border:1px solid #dde5ee;border-radius:12px;padding:18px}h1{margin-top:0;font-size:1.3rem}p{line-height:1.5;color:#4b5563}</style></head><body><main><h1>${title}</h1><p>${text}</p></main></body></html>`;

if (!reqPageId) {
  return [{
    json: {
      statusCode: 400,
      body: htmlError('Bad Request', 'Fehlende pageId im Pfad.'),
      contentType: 'text/html; charset=utf-8'
    }
  }];
}

if (!storedToken) {
  return [{
    json: {
      statusCode: 404,
      body: htmlError('Nicht gefunden', 'Diese News-Seite existiert nicht oder wurde bereits entfernt.'),
      contentType: 'text/html; charset=utf-8'
    }
  }];
}

if (!providedToken || providedToken !== storedToken) {
  return [{
    json: {
      statusCode: 403,
      body: htmlError('Zugriff verweigert', 'Der Link ist ungueltig oder unvollstaendig.'),
      contentType: 'text/html; charset=utf-8'
    }
  }];
}

const expiresTs = expiresAtRaw ? Date.parse(String(expiresAtRaw)) : NaN;
if (Number.isFinite(expiresTs) && Date.now() > expiresTs) {
  return [{
    json: {
      statusCode: 410,
      body: htmlError('Abgelaufen', 'Diese News-Seite ist abgelaufen.'),
      contentType: 'text/html; charset=utf-8'
    }
  }];
}

let body = '';
try {
  body = Buffer.from(htmlB64, 'base64').toString('utf8');
} catch {
  body = htmlError('Fehler', 'Die gespeicherte News-Seite konnte nicht gelesen werden.');
  return [{
    json: {
      statusCode: 500,
      body,
      contentType: 'text/html; charset=utf-8'
    }
  }];
}

return [{
  json: {
    statusCode: 200,
    body,
    contentType: 'text/html; charset=utf-8'
  }
}];
